// Extracts plain-text content from each docs/*.md lesson file so the instant
// client-side search (src/lib/fuzzy.js + src/components/Search/SearchModal.jsx)
// can match against full lesson content, not just title/tags/section.
//
// Runs automatically before `npm start` / `npm run build` (see package.json).
// Output is generated — do not edit src/data/lessonContent.generated.js by hand.

const fs = require("fs");
const path = require("path");

const DOCS_DIR = path.join(__dirname, "..", "docs");
const OUT_FILE = path.join(
  __dirname,
  "..",
  "src",
  "data",
  "lessonContent.generated.js"
);

function extractFrontmatterId(text) {
  const m = text.match(/^---\n([\s\S]*?)\n---\n?/);
  if (!m) return { id: null, body: text };
  const idMatch = m[1].match(/^id:\s*(.+)$/m);
  return { id: idMatch ? idMatch[1].trim() : null, body: text.slice(m[0].length) };
}

function stripMarkdown(body) {
  const codeBlocks = [];
  const inlineCodes = [];

  // Pull code out FIRST and stash it untouched — the prose cleanup below
  // (in particular the emphasis-marker strip) would otherwise mangle
  // identifiers like push_back or unordered_map by eating underscores.
  let text = body.replace(/```[^\n]*\n([\s\S]*?)```/g, (_, code) => {
    codeBlocks.push(code.trim());
    return "\u0000CODEBLOCK" + (codeBlocks.length - 1) + "\u0000";
  });

  text = text.replace(/`([^`]+)`/g, (_, code) => {
    inlineCodes.push(code);
    return "\u0000INLINECODE" + (inlineCodes.length - 1) + "\u0000";
  });

  text = text
    // images: drop entirely (alt text isn't meaningful prose here)
    .replace(/!\[[^\]]*\]\([^)]*\)/g, " ")
    // links: keep the visible text, drop the URL
    .replace(/\[([^\]]+)\]\([^)]*\)/g, "$1")
    // headings / blockquotes / list markers at line start
    .replace(/^#{1,6}\s+/gm, "")
    .replace(/^>\s?/gm, "")
    .replace(/^[-*+]\s+/gm, "")
    .replace(/^\d+\.\s+/gm, "")
    // paired emphasis markers only — never a lone _/* , since an unpaired
    // underscore is almost always a real identifier written outside
    // backticks (e.g. a heading "## lower_bound" with no code formatting),
    // not markdown italics. Requiring a matching pair avoids corrupting it.
    .replace(/\*\*\*(.+?)\*\*\*/g, "$1")
    .replace(/\*\*(.+?)\*\*/g, "$1")
    .replace(/(?<![a-zA-Z0-9*])\*([^*\n]+)\*(?![a-zA-Z0-9*])/g, "$1")
    .replace(/__([^_]+)__/g, "$1")
    .replace(/(?<![a-zA-Z0-9_])_([^_\n]+)_(?![a-zA-Z0-9_])/g, "$1");

  // Restore code content exactly as written.
  text = text
    .replace(/\u0000CODEBLOCK(\d+)\u0000/g, (_, i) => " " + codeBlocks[Number(i)] + " ")
    .replace(/\u0000INLINECODE(\d+)\u0000/g, (_, i) => inlineCodes[Number(i)]);

  return text.replace(/\r\n/g, "\n").replace(/\s+/g, " ").trim();
}

function main() {
  if (!fs.existsSync(DOCS_DIR)) {
    console.warn("build-search-index: no docs/ directory found, skipping.");
    return;
  }

  const files = fs.readdirSync(DOCS_DIR).filter((f) => f.endsWith(".md"));
  const out = {};

  for (const file of files) {
    const raw = fs.readFileSync(path.join(DOCS_DIR, file), "utf8");
    const { id, body } = extractFrontmatterId(raw.replace(/\r\n/g, "\n"));
    const slug = id || file.replace(/\.md$/, "");
    out[slug] = stripMarkdown(body);
  }

  const header =
    "// AUTO-GENERATED by scripts/build-search-index.js — do not edit by hand.\n" +
    "// Regenerated automatically before `npm start` / `npm run build`.\n\n";
  const contents =
    header + "export const lessonContent = " + JSON.stringify(out, null, 2) + ";\n";

  fs.mkdirSync(path.dirname(OUT_FILE), { recursive: true });
  fs.writeFileSync(OUT_FILE, contents, "utf8");
  console.log(
    "build-search-index: indexed " +
      files.length +
      " lesson(s) -> " +
      path.relative(process.cwd(), OUT_FILE)
  );
}

main();
